(window.webpackJsonp=window.webpackJsonp||[]).push([[867],{1136:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{boolean}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> circularArrayLoop = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> n = nums.length;\\n  <span class=\\"hljs-keyword\\">for</span> (<span class=\\"hljs-keyword\\">let</span> i = <span class=\\"hljs-number\\">0</span>; i &lt; n; i++) {\\n    <span class=\\"hljs-keyword\\">if</span> (nums[i] == <span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">continue</span>;\\n    <span class=\\"hljs-keyword\\">let</span> j = i, k = getIndex(i);\\n    <span class=\\"hljs-keyword\\">while</span> (nums[k] * nums[i] &gt; <span class=\\"hljs-number\\">0</span> &amp;&amp; nums[getIndex(k)] * nums[i] &gt; <span class=\\"hljs-number\\">0</span>) {\\n      <span class=\\"hljs-keyword\\">if</span> (j == k) {\\n        <span class=\\"hljs-keyword\\">if</span> (j == getIndex(j))<span class=\\"hljs-keyword\\">break</span>;\\n        <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>;\\n      }\\n      j = getIndex(j);\\n      k = getIndex(getIndex(k));\\n    }\\n    j = i;\\n    <span class=\\"hljs-keyword\\">let</span> val = nums[i];\\n    <span class=\\"hljs-keyword\\">while</span> (nums[j] * val &gt; <span class=\\"hljs-number\\">0</span>) {\\n        <span class=\\"hljs-keyword\\">let</span> next = getIndex(j);\\n        nums[j] = <span class=\\"hljs-number\\">0</span>;\\n        j = next;\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>;    \\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">getIndex</span>(<span class=\\"hljs-params\\">i</span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> ((i+nums[i]) % n + n) % n\\n    <span class=\\"hljs-comment\\">// let nxtI=i+nums[i]</span>\\n    <span class=\\"hljs-comment\\">// while(nxtI&lt;0)nxtI+=n</span>\\n    <span class=\\"hljs-comment\\">// return nxtI % n</span>\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"circular-array-loop","hasThinking":false,"content":"<p>\u5b58\u5728\u4e00\u4e2a\u4e0d\u542b <code>0</code> \u7684<strong> \u73af\u5f62 </strong>\u6570\u7ec4\xa0<code>nums</code> \uff0c\u6bcf\u4e2a <code>nums[i]</code> \u90fd\u8868\u793a\u4f4d\u4e8e\u4e0b\u6807 <code>i</code> \u7684\u89d2\u8272\u5e94\u8be5\u5411\u524d\u6216\u5411\u540e\u79fb\u52a8\u7684\u4e0b\u6807\u4e2a\u6570\uff1a</p>\\n\\n<ul>\\n\\t<li>\u5982\u679c <code>nums[i]</code> \u662f\u6b63\u6570\uff0c<strong>\u5411\u524d</strong> \u79fb\u52a8 <code>nums[i]</code> \u6b65</li>\\n\\t<li>\u5982\u679c\xa0<code>nums[i]</code> \u662f\u8d1f\u6570\uff0c<strong>\u5411\u540e</strong> \u79fb\u52a8 <code>nums[i]</code> \u6b65</li>\\n</ul>\\n\\n<p>\u56e0\u4e3a\u6570\u7ec4\u662f <strong>\u73af\u5f62</strong> \u7684\uff0c\u6240\u4ee5\u53ef\u4ee5\u5047\u8bbe\u4ece\u6700\u540e\u4e00\u4e2a\u5143\u7d20\u5411\u524d\u79fb\u52a8\u4e00\u6b65\u4f1a\u5230\u8fbe\u7b2c\u4e00\u4e2a\u5143\u7d20\uff0c\u800c\u7b2c\u4e00\u4e2a\u5143\u7d20\u5411\u540e\u79fb\u52a8\u4e00\u6b65\u4f1a\u5230\u8fbe\u6700\u540e\u4e00\u4e2a\u5143\u7d20\u3002</p>\\n\\n<p>\u6570\u7ec4\u4e2d\u7684 <strong>\u5faa\u73af</strong> \u7531\u957f\u5ea6\u4e3a <code>k</code> \u7684\u4e0b\u6807\u5e8f\u5217 <code>seq</code> \uff1a</p>\\n\\n<ul>\\n\\t<li>\u9075\u5faa\u4e0a\u8ff0\u79fb\u52a8\u89c4\u5219\u5c06\u5bfc\u81f4\u91cd\u590d\u4e0b\u6807\u5e8f\u5217 <code>seq[0] -> seq[1] -> ... -> seq[k - 1] -> seq[0] -> ...</code></li>\\n\\t<li>\u6240\u6709 <code>nums[seq[j]]</code> \u5e94\u5f53\u4e0d\u662f <strong>\u5168\u6b63</strong> \u5c31\u662f <strong>\u5168\u8d1f</strong></li>\\n\\t<li><code>k > 1</code></li>\\n</ul>\\n\\n<p>\u5982\u679c <code>nums</code> \u4e2d\u5b58\u5728\u5faa\u73af\uff0c\u8fd4\u56de <code>true</code> \uff1b\u5426\u5219\uff0c\u8fd4\u56de<em> </em><code>false</code><em> </em>\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [2,-1,1,2,2]\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong>\u5b58\u5728\u5faa\u73af\uff0c\u6309\u4e0b\u6807 0 -> 2 -> 3 -> 0 \u3002\u5faa\u73af\u957f\u5ea6\u4e3a 3 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [-1,2]\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n<strong>\u89e3\u91ca\uff1a</strong>\u6309\u4e0b\u6807 1 -> 1 -> 1 ... \u7684\u8fd0\u52a8\u65e0\u6cd5\u6784\u6210\u5faa\u73af\uff0c\u56e0\u4e3a\u5faa\u73af\u7684\u957f\u5ea6\u4e3a 1 \u3002\u6839\u636e\u5b9a\u4e49\uff0c\u5faa\u73af\u7684\u957f\u5ea6\u5fc5\u987b\u5927\u4e8e 1 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3:</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [-2,1,-1,-2,-2]\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n<strong>\u89e3\u91ca\uff1a</strong>\u6309\u4e0b\u6807 1 -> 2 -> 1 -> ... \u7684\u8fd0\u52a8\u65e0\u6cd5\u6784\u6210\u5faa\u73af\uff0c\u56e0\u4e3a nums[1] \u662f\u6b63\u6570\uff0c\u800c nums[2] \u662f\u8d1f\u6570\u3002\\n\u6240\u6709 nums[seq[j]] \u5e94\u5f53\u4e0d\u662f\u5168\u6b63\u5c31\u662f\u5168\u8d1f\u3002</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= nums.length <= 5000</code></li>\\n\\t<li><code>-1000 <= nums[i] <= 1000</code></li>\\n\\t<li><code>nums[i] != 0</code></li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u8fdb\u9636\uff1a</strong>\u4f60\u80fd\u8bbe\u8ba1\u4e00\u4e2a\u65f6\u95f4\u590d\u6742\u5ea6\u4e3a <code>O(n)</code> \u4e14\u989d\u5916\u7a7a\u95f4\u590d\u6742\u5ea6\u4e3a <code>O(1)</code> \u7684\u7b97\u6cd5\u5417\uff1f</p>\\n","title":"457. \u73af\u5f62\u6570\u7ec4\u662f\u5426\u5b58\u5728\u5faa\u73af","relatedTags":["\u6570\u7ec4","\u53cc\u6307\u9488"],"difficult":"Middle","lang":["javascript"],"uniqueID":"457"}')}}]);